#include "CabinetIR.h"
namespace SonicForge { void CabinetIR::prepare(double sampleRate, int blockSize, int channels){ sr=sampleRate; hp.resize(channels); lp.resize(channels); notch.resize(channels); juce::dsp::ProcessSpec spec{sampleRate,(juce::uint32)blockSize,(juce::uint32)channels}; for(auto* v:{&hp,&lp,&notch}) for(auto& f:*v) f.prepare(spec); }
void CabinetIR::process(juce::AudioBuffer<float>& b, float mix, int amp){ float lowCut = amp==5?75.f:90.f; float hiCut = amp==6?7200.f:5600.f; for(int c=0;c<b.getNumChannels();++c){ *hp[c].coefficients=*juce::dsp::IIR::Coefficients<float>::makeHighPass(sr,lowCut,.707f); *lp[c].coefficients=*juce::dsp::IIR::Coefficients<float>::makeLowPass(sr,hiCut,.707f); *notch[c].coefficients=*juce::dsp::IIR::Coefficients<float>::makePeakFilter(sr,3200.f,.8f,juce::Decibels::decibelsToGain(-3.5f)); juce::AudioBuffer<float> dry(1,b.getNumSamples()); dry.copyFrom(0,0,b,c,0,b.getNumSamples()); juce::dsp::AudioBlock<float> block(b); auto single=block.getSingleChannelBlock((size_t)c); juce::dsp::ProcessContextReplacing<float> ctx(single); hp[c].process(ctx); notch[c].process(ctx); lp[c].process(ctx); auto*d=b.getWritePointer(c); auto*dr=dry.getReadPointer(0); for(int i=0;i<b.getNumSamples();++i)d[i]=dr[i]*(1.f-mix)+d[i]*mix; }} }
